let page = 1;
let keywords = "";
let batchSize = 100;
let offset = 0;

try {
    const prev = $('Wait Semantic').first().json;
    page = prev.page_counter;
    keywords = prev.Keywords; 
    batchSize = prev.batch_size;
    offset = prev.offset;
} catch(e) {
    try {
        const init = $('Init Semantic').first().json;
        page = init.page_counter;
        keywords = init.Keywords;
        batchSize = init.batch_size;
        offset = init.offset;
    } catch(e2){}
}

const results = items[0].json.data || [];
const explodedAuthors = [];

results.forEach(r => {
    const doi = r.externalIds && r.externalIds.DOI ? r.externalIds.DOI : "No DOI";
    const title = r.title || "No Title";
    const year = r.year || "n/d";
    const authors = r.authors || [];

    if (authors.length === 0) {
        explodedAuthors.push({
            json: {
                PAPER_TITLE: title, DOI: doi, YEAR: year,
                AUTHOR_NAME: "Unknown", AUTHOR_POSITION: "Unknown", AUTHOR_ID: "NO_ID",
                AFFILIATION_PAPER: "No data", GEOLOCATION_COUNTRY_RAW: "UNKNOWN", 
                SOURCE_DB: "SemanticScholar",
                page_num: page, search_term: keywords, start_index: offset
            }
        });
    } else {
        // TÉCNICA LUKAS: Extraer todos los autores
        authors.forEach((auth, index) => {
            let position = "middle";
            if (index === 0) position = "first";
            else if (index === authors.length - 1) position = "last";

            let affiliation = "No affiliation";
            if (auth.affiliations && Array.isArray(auth.affiliations) && auth.affiliations.length > 0) {
                affiliation = auth.affiliations.map(a => typeof a === 'object' ? a.name || a.affiliation || JSON.stringify(a) : a).join(" | ");
            }

            explodedAuthors.push({
                json: {
                    PAPER_TITLE: title, DOI: doi, YEAR: year,
                    AUTHOR_NAME: auth.name || "Unknown",
                    AUTHOR_POSITION: position,
                    AUTHOR_ID: auth.authorId || "NO_ID", // <-- CLAVE PARA EL PASO 2
                    AFFILIATION_PAPER: affiliation,
                    GEOLOCATION_COUNTRY_RAW: "Need extraction", 
                    SOURCE_DB: "SemanticScholar",
                    page_num: page, search_term: keywords, start_index: offset
                }
            });
        });
    }
});

return explodedAuthors;

const results = items[0].json['search-results']?.entry || [];
let pageCounter = 1;
let currentStart = 0;

try {
    const prevLoop = $('Wait SC1').first().json;
    pageCounter = prevLoop.page_counter;
    currentStart = prevLoop.start_index;
} catch(e) {
    try {
        const init = $('Init Scopus').first().json;
        pageCounter = init.page_counter;
        currentStart = init.start_index;
    } catch(e2) {}
}

const explodedAuthors = [];

results.forEach(r => {
    const title = r['dc:title'] || "No Title";
    const doi = r['prism:doi'] || "No DOI";
    const year = r['prism:coverDate'] ? r['prism:coverDate'].substring(0,4) : "n/d";

    // CORRECCIÓN: Forzar que siempre sean arrays
    let rawAffiliations = r.affiliation || [];
    const affiliations = Array.isArray(rawAffiliations) ? rawAffiliations : [rawAffiliations];

    let rawAuthors = r.author || [];
    const authors = Array.isArray(rawAuthors) ? rawAuthors : [rawAuthors]; 

    // Mapeo de afiliaciones de Scopus
    let affilMap = {};
    affiliations.forEach(aff => {
        let id = aff.afid || aff['@id'];
        if(id) {
            affilMap[id] = {
                name: aff.affilname || "No affiliation",
                country: aff['affiliation-country'] || "UNKNOWN"
            };
        }
    });

    if(!authors || authors.length === 0) {
        explodedAuthors.push({
            json: {
                PAPER_TITLE: title, DOI: doi, YEAR: year,
                AUTHOR_NAME: "Unknown", AUTHOR_POSITION: "Unknown", AUTHOR_ID: "NO_ID",
                AFFILIATION_PAPER: "No data", GEOLOCATION_COUNTRY_RAW: "UNKNOWN",
                SOURCE_DB: "Scopus", page_num: pageCounter, current_start_index: currentStart
            }
        });
    } else {
        authors.forEach((auth, index) => {
            let position = "middle";
            if (index === 0) position = "first";
            else if (index === authors.length - 1) position = "last";

            let authName = auth.authname || `${auth['given-name'] || ''} ${auth.surname || ''}`.trim() || "Unknown";
            let authId = auth.authid || "NO_ID";

            let authAffil = "No affiliation";
            let rawCountry = "UNKNOWN";

            if(auth.afid) {
                let afids = Array.isArray(auth.afid) ? auth.afid : [auth.afid];
                let aNames = [];
                let aCountries = [];
                afids.forEach(idObj => {
                    let id = (typeof idObj === 'object' && idObj !== null) ? (idObj['$'] || idObj['@id'] || idObj.afid) : idObj;
                    if(id && affilMap[id]) {
                        aNames.push(affilMap[id].name);
                        aCountries.push(affilMap[id].country);
                    }
                });
                if(aNames.length > 0) authAffil = [...new Set(aNames)].join(" | ");
                if(aCountries.length > 0) rawCountry = aCountries.find(c => c !== "UNKNOWN") || "UNKNOWN";
            }

            // Fallback de contingencia si no engancha el ID
            if (authAffil === "No affiliation" && affiliations.length === 1) {
                authAffil = affiliations[0].affilname || "No affiliation";
                rawCountry = affiliations[0]['affiliation-country'] || "UNKNOWN";
            } else if (authAffil === "No affiliation" && affiliations.length > 0) {
                authAffil = affiliations.map(a => a.affilname).filter(Boolean).join(" | ") || "No affiliation";
                let countryList = affiliations.map(a => a['affiliation-country']).filter(c => c && c !== "UNKNOWN");
                rawCountry = countryList.length > 0 ? countryList[0] : "UNKNOWN";
            }

            explodedAuthors.push({
                json: {
                    PAPER_TITLE: title, DOI: doi, YEAR: year,
                    AUTHOR_NAME: authName, AUTHOR_POSITION: position,
                    AUTHOR_ID: authId,
                    AFFILIATION_PAPER: authAffil,
                    GEOLOCATION_COUNTRY_RAW: rawCountry, 
                    SOURCE_DB: "Scopus", page_num: pageCounter, current_start_index: currentStart
                }
            });
        });
    }
});

return explodedAuthors;

let pageCounter = 1;
let currentRetStart = 0;
try {
    const prevLoop = $('Wait PM1').first().json;
    pageCounter = prevLoop.page_counter;
    currentRetStart = prevLoop.retstart;
} catch(e) {
    try {
        const init = $('Init PubMed').first().json;
        pageCounter = init.page_counter;
        currentRetStart = init.retstart;
    } catch(e2) {}
}

const explodedAuthors = [];

items.forEach(item => {
    const paper = item.json;
    const meta = paper.MedlineCitation?.Article || {}; 

    // 1. Limpiar Título
    let titleRaw = meta.ArticleTitle || "No Title";
    let title = typeof titleRaw === 'object' ? (titleRaw._ || "No Title") : titleRaw;

    // 2. Extraer Año
    const year = meta.Journal?.JournalIssue?.PubDate?.Year || "n/d";

    // 3. Extraer DOI
    let doi = "No DOI";
    if (paper.PubmedData?.ArticleIdList?.ArticleId) {
      const idList = paper.PubmedData.ArticleIdList.ArticleId;
      const doiObj = Array.isArray(idList) 
          ? idList.find(i => i.IdType === 'doi') 
          : (idList.IdType === 'doi' ? idList : null);

      if (doiObj) doi = typeof doiObj === 'object' ? (doiObj._ || "No DOI") : doiObj;
    }

    // 4. EXTRAER KEYWORDS MÉDICAS (MeSH Terms)
    let keywords = "No data";
    const meshList = paper.MedlineCitation?.MeshHeadingList?.MeshHeading;
    if (meshList) {
        const meshes = Array.isArray(meshList) ? meshList : [meshList];
        keywords = meshes.slice(0, 5).map(m => m.DescriptorName._ || m.DescriptorName).join(", ");
    }

    const authorList = meta.AuthorList?.Author;

    if (!authorList) {
        explodedAuthors.push({
            json: {
                PAPER_TITLE: title,
                DOI: doi,
                YEAR: year,
                AUTHOR_NAME: "No data",
                AUTHOR_POSITION: "No data",
                AUTHOR_ID: "NO_ID",
                ORCID: "NO_ORCID", // <--- COLUMNA AÑADIDA
                AFFILIATION: "No data",
                GEOLOCATION_COUNTRY: "Need LLM extraction",
                SOURCE_DB: "PubMed",
                search_term: "Inherited from search",
                page_num: pageCounter,
                start_index: currentRetStart,
                scholar_id: "N/A (PubMed)",
                hindex: "N/A (PubMed)",
                i10index: "N/A (PubMed)",
                total_citations: "N/A (PubMed)",
                consecutive_years: "N/A (PubMed)",
                seniority: "Clinical Data",
                keywords: keywords
            }
        });
        return;
    }

    const authors = Array.isArray(authorList) ? authorList : [authorList];

    authors.forEach((auth, index) => {
        let authorName = "Unknown";
        if (auth.LastName || auth.ForeName) {
            authorName = `${auth.ForeName || ''} ${auth.LastName || ''}`.trim();
        } else if (auth.CollectiveName) {
            authorName = auth.CollectiveName._ || auth.CollectiveName;
        }

        let position = "middle";
        if (index === 0) position = "first";
        else if (index === authors.length - 1) position = "last";

        // Limpiar Afiliación
        let affiliation = "No affiliation";
        if (auth.AffiliationInfo) {
            const affInfo = Array.isArray(auth.AffiliationInfo) ? auth.AffiliationInfo[0] : auth.AffiliationInfo;
            if (affInfo.Affiliation) {
                affiliation = typeof affInfo.Affiliation === 'object' ? (affInfo.Affiliation._ || "No affiliation") : affInfo.Affiliation;
            }
        }

        // --- NUEVA LÓGICA DE ORCID Y AUTHOR ID ---
        let orcid = "NO_ORCID";
        let authorId = "NO_ID"; // Por defecto no hay ID interno en PubMed

        if (auth.Identifier) {
            const idInfoArray = Array.isArray(auth.Identifier) ? auth.Identifier : [auth.Identifier];

            // Buscamos si alguno de los identificadores es el ORCID
            const orcidObj = idInfoArray.find(id => id.Source === "ORCID");

            if (orcidObj) {
                let rawOrcid = typeof orcidObj === 'object' ? (orcidObj._ || "NO_ORCID") : orcidObj;
                orcid = rawOrcid.replace("http://orcid.org/", "").replace("https://orcid.org/", "");
                // Como PubMed no tiene ID propio, copiamos el ORCID al AUTHOR_ID para mantener la consistencia
                authorId = orcid; 
            }
        }

        explodedAuthors.push({
            json: {
                PAPER_TITLE: title,
                DOI: doi,
                YEAR: year,
                AUTHOR_NAME: authorName,
                AUTHOR_POSITION: position,
                AUTHOR_ID: authorId,
                ORCID: orcid, // <--- COLUMNA AÑADIDA
                AFFILIATION: affiliation,
                GEOLOCATION_COUNTRY: "Need LLM extraction", 
                SOURCE_DB: "PubMed",
                search_term: "Inherited from search",
                page_num: pageCounter,
                start_index: currentRetStart,
                scholar_id: authorId !== "NO_ID" ? authorId : "N/A (PubMed)",
                hindex: "N/A (PubMed)",
                i10index: "N/A (PubMed)",
                total_citations: "N/A (PubMed)",
                consecutive_years: "N/A (PubMed)",
                seniority: "Clinical Data",
                keywords: keywords
            }
        });
    });
});

return explodedAuthors;

const rootData = $("Code in JavaScript").first().json;
const page = rootData.page || 1;
const keywords = rootData.Keywords || "Unknown";
const batchSize = rootData.batch_size || 50;

const response = items[0].json; 
const papers = response.results || [];

const explodedAuthors = [];

papers.forEach((paper, index) => {
  const authorships = paper.authorships || [];

  // Calculamos el start_index equivalente para igualar la lógica de Scholar
  const batchStartIndex = (page - 1) * batchSize;

  // Extraer información base del paper
  const doi = paper.doi ? paper.doi.replace("https://doi.org/", "") : "No DOI";
  const title = paper.title || "No Title";
  const year = paper.publication_year || "n/d";

  if (authorships.length === 0) {
      // Si no hay autores registrados, guardamos el paper para no perderlo
      explodedAuthors.push({
          json: {
              PAPER_TITLE: title,
              DOI: doi,
              YEAR: year,
              AUTHOR_NAME: "Unknown",
              AUTHOR_POSITION: "Unknown",
              AUTHOR_ID: "NO_ID",
              ORCID: "NO_ORCID", // <--- NUEVO
              AFFILIATION: "No data",
              GEOLOCATION_COUNTRY: "UNKNOWN",
              SOURCE_DB: "OpenAlex",
              search_term: keywords,
              page_num: page,
              start_index: batchStartIndex
          }
      });
  } else {
      // Iteramos sobre CADA AUTOR para crear UNA FILA POR AUTOR (Extracción Total)
      authorships.forEach(auth => {

          let authorId = "NO_ID";
          let orcid = "NO_ORCID"; // <--- NUEVO

          if (auth.author) {
              // 1. Extraer ID de Autor de OpenAlex
              if (auth.author.id) {
                  authorId = auth.author.id.split('/').pop(); 
              }
              // 2. Extraer ORCID (Limpiando la URL) // <--- NUEVO
              if (auth.author.orcid) {
                  orcid = auth.author.orcid.replace("https://orcid.org/", "").replace("http://orcid.org/", "");
              }
          }

          // Extraer instituciones
          const institutions = auth.institutions && auth.institutions.length > 0
              ? auth.institutions.map(i => i.display_name).join(" | ") 
              : "No affiliation";

          // Extraer países
          const countries = auth.countries && auth.countries.length > 0 
              ? auth.countries.join(" | ") 
              : "UNKNOWN";

          explodedAuthors.push({
              json: {
                  PAPER_TITLE: title,
                  DOI: doi,
                  YEAR: year,
                  AUTHOR_NAME: auth.author ? auth.author.display_name : "Unknown",
                  AUTHOR_POSITION: auth.author_position || "Unknown",
                  AUTHOR_ID: authorId,
                  ORCID: orcid, // <--- NUEVO
                  AFFILIATION: institutions,
                  GEOLOCATION_COUNTRY: countries,
                  SOURCE_DB: "OpenAlex",
                  search_term: keywords,
                  page_num: page,
                  start_index: batchStartIndex
              }
          });
      });
  }
});

return explodedAuthors;

// 1. Rescatamos TODA la info original del lote actual
const originalItems = $('Loop Over Items1').all();

return items.map((item, index) => {
    // 2. Leemos el país limpio extraído por la IA
    let rawCountry = item.json.output?.country_code || item.json.country_code || "UNKNOWN";
    let cleanCountry = rawCountry.trim().replace(/[^a-zA-Z]/g, "").toUpperCase();

    // 3. Clonamos la fila original completa para no perder ninguna columna
    let originalData = { ...originalItems[index].json };

    // 4. Inyectamos el país (Logic-Lock de 2 letras)
    if (cleanCountry.length === 2) {
        originalData.GEOLOCATION_COUNTRY = cleanCountry;
    } else {
        originalData.GEOLOCATION_COUNTRY = "UNKNOWN";
    }

    // 5. Devolvemos el JSON con toda la info junta
    return { json: originalData };
});

const results = items[0].json.organic_results || [];
let pageCounter = 1; let currentStart = 0; let queryUsada = ""; 

// LÓGICA DE BUCLE: Primero revisamos si venimos del Wait, si no, tomamos del Init
try {
    const prevLoop = $('Wait1').first().json;
    pageCounter = prevLoop.page_counter;
    currentStart = prevLoop.start_index;
    queryUsada = prevLoop.Keywords;
} catch(e) {
    try {
        const init = $('Init Google Sholar').first().json;
        pageCounter = init.page_counter;
        currentStart = init.start_index;
        queryUsada = init.Keywords;
    } catch(e2) {}
}

const targetAuthors = [];

results.forEach(r => {
    const title = r.title || "No Title";
    const link = r.link || "No link";
    const summary = r.publication_info?.summary || "";
    const yearMatch = summary.match(/\b(19|20)\d{2}\b/);
    const yearExtracted = yearMatch ? yearMatch[0] : "n/d";

    const authorsArray = r.publication_info?.authors || [];

    if (authorsArray.length === 0) {
        targetAuthors.push({
            json: {
                PAPER_TITLE: title, DOI: link, YEAR: yearExtracted,
                AUTHOR_NAME: "Unknown", AUTHOR_POSITION: "first",
                AUTHOR_ID: "NO_ID", AFFILIATION: "No Profile in Scholar",
                GEOLOCATION_COUNTRY: "UNKNOWN", SOURCE_DB: "GoogleScholar", 
                search_term: queryUsada, page_num: pageCounter, start_index: currentStart
            }
        });
    } else {
        // TÉCNICA LUKAS: Solo Primer Autor
        const firstAuthor = authorsArray[0];
        targetAuthors.push({
            json: {
                PAPER_TITLE: title, DOI: link, YEAR: yearExtracted,
                AUTHOR_NAME: firstAuthor.name, AUTHOR_POSITION: "first",
                AUTHOR_ID: firstAuthor.author_id || "NO_ID", 
                AFFILIATION: "Pending...", 
                GEOLOCATION_COUNTRY: "Pending...",
                SOURCE_DB: "GoogleScholar", search_term: queryUsada, 
                page_num: pageCounter, start_index: currentStart
            }
        });

        // TÉCNICA LUKAS: Solo Último Autor
        if (authorsArray.length > 1) {
            const lastAuthor = authorsArray[authorsArray.length - 1];
            targetAuthors.push({
                json: {
                    PAPER_TITLE: title, DOI: link, YEAR: yearExtracted,
                    AUTHOR_NAME: lastAuthor.name, AUTHOR_POSITION: "last",
                    AUTHOR_ID: lastAuthor.author_id || "NO_ID",
                    AFFILIATION: "Pending...",
                    GEOLOCATION_COUNTRY: "Pending...",
                    SOURCE_DB: "GoogleScholar", search_term: queryUsada, 
                    page_num: pageCounter, start_index: currentStart
                }
            });
        }
    }
});

return targetAuthors;

// 1. Rescatamos los datos del autor original de esta iteración exacta
let originalData = { ...$('Loop Authors Scholar').item.json };

// 2. Rescatamos el perfil completo
let profile = $('HTTP Request1').item.json;

// 3. Rescatamos la extracción del país (LLM)
let llmOutput = items[0].json;

// --- DATOS BÁSICOS Y LLM ---
let affiliationText = profile.author?.affiliations;
originalData.AFFILIATION = affiliationText ? affiliationText : "No affiliation listed in profile";

let rawCountry = "UNKNOWN";
if (llmOutput.output && llmOutput.output.country_code) rawCountry = llmOutput.output.country_code;
else if (llmOutput.country_code) rawCountry = llmOutput.country_code;

let cleanCountry = rawCountry.trim().replace(/[^a-zA-Z]/g, "").toUpperCase();
originalData.GEOLOCATION_COUNTRY = (cleanCountry.length === 2 && cleanCountry !== "NO") ? cleanCountry : "UNKNOWN";

// --- MÉTRICAS PURAS DE IMPACTO ---
let hindex = "N/A"; let i10index = "N/A"; let total_citations = "N/A";

if (profile.cited_by && Array.isArray(profile.cited_by.table)) {
    profile.cited_by.table.forEach(row => {
        if (row.citations !== undefined) total_citations = row.citations.all ?? "N/A";
        if (row.h_index !== undefined) hindex = row.h_index.all ?? "N/A";
        if (row.i10_index !== undefined) i10index = row.i10_index.all ?? "N/A";
    });
}

// --- INTERESES / KEYWORDS ---
originalData.interests = (profile.author && Array.isArray(profile.author.interests)) 
    ? profile.author.interests.map(i => i.title).join(" | ") 
    : "None";

// --- CÁLCULO DE SENIORITY Y RACHA ---
let consecutive_years = 0;
let seniority = "Unknown";

if (profile.articles && Array.isArray(profile.articles) && profile.articles.length > 0) {
    let years = profile.articles.map(a => parseInt(a.year)).filter(y => !isNaN(y));

    if (years.length > 0) {
        let uniqueYears = [...new Set(years)].sort((a,b) => b - a);

        consecutive_years = 1;
        let current = uniqueYears[0];
        for (let i = 1; i < uniqueYears.length; i++) {
            if (uniqueYears[i] === current - 1) {
                consecutive_years++;
                current = uniqueYears[i];
            } else break; 
        }

        let firstYear = Math.min(...uniqueYears);
        let currentYear = new Date().getFullYear();
        let careerLength = currentYear - firstYear; 

        if (careerLength > 15) seniority = "Senior";
        else if (careerLength >= 5) seniority = "Mid";
        else seniority = "Early";
    }
}

// Inyectar resultados de vuelta al objeto
originalData.total_citations = total_citations;
originalData.hindex = hindex;
originalData.i10index = i10index;
originalData.consecutive_years = consecutive_years;
originalData.seniority = seniority;

// Retornamos el item único procesado
return { json: originalData };

const rootData = $('Loop Over Items').first().json;
const keywords = rootData['BOOLEAN SEARCHING STRING'];
const batchSize = rootData['BATCH SIZE'] || 50; 

const page = items[0].json.page || 1;

let yearRange = rootData['YEAR RANGE'];

if (!yearRange) {
    try {
        yearRange = $('Init Open Alex').first().json.Year;
    } catch(e) {
        yearRange = null; 
    }
}

const encodedQuery = encodeURIComponent(keywords);
const email = "isaac.gavilanes@yachaytech.edu.ec";
const finalLimit = batchSize > 200 ? 200 : batchSize;

let filterParam = `title_and_abstract.search:${encodedQuery}`;

if (yearRange) {
    filterParam += `,publication_year:${yearRange}`;
}

const url = `https://api.openalex.org/works?filter=${filterParam}&per_page=${finalLimit}&page=${page}&mailto=${email}`;

return [
  {
    json: {
      Keywords: keywords,
      page: page,
      generated_url: url,
      batch_size: finalLimit,
      Year: yearRange 
    }
  }
];

// 1. Rescatamos la fila original del Paper
const originalData = $('Loop Authors OpenAlex').item.json;

// 2. Rescatamos los datos del perfil del Autor de OpenAlex
const authorProfile = items[0].json;

// --- EXTRACCIÓN DE MÉTRICAS BASE ---
const hindex = authorProfile.summary_stats ? authorProfile.summary_stats.h_index : 0;
const i10index = authorProfile.summary_stats ? authorProfile.summary_stats.i10_index : 0;
const total_citations = authorProfile.cited_by_count || 0;

// --- EXTRACCIÓN DE KEYWORDS / INTERESES ---
let keywords = "No data";
if (authorProfile.x_concepts && authorProfile.x_concepts.length > 0) {
    // Tomamos los 5 conceptos principales que OpenAlex le asigna
    keywords = authorProfile.x_concepts.slice(0, 5).map(c => c.display_name).join(", ");
}

// --- AFILIACIÓN HISTÓRICA ---
let affiliation = originalData.AFFILIATION; 
if (authorProfile.last_known_institution && authorProfile.last_known_institution.display_name) {
    affiliation = authorProfile.last_known_institution.display_name;
}

// --- CÁLCULO DE AÑOS CONSECUTIVOS PUBLICANDO ---
let consecutive_years = 0;
if (authorProfile.counts_by_year && authorProfile.counts_by_year.length > 0) {
    // Extraemos solo los años donde publicó al menos 1 paper y ordenamos de mayor a menor
    const years = authorProfile.counts_by_year
        .filter(y => y.works_count > 0)
        .map(y => y.year)
        .sort((a, b) => b - a);

    if (years.length > 0) {
        consecutive_years = 1; // El primer año cuenta
        let currentYearCheck = years[0];

        for (let i = 1; i < years.length; i++) {
            if (years[i] === currentYearCheck - 1) {
                consecutive_years++;
                currentYearCheck = years[i];
            } else {
                break; // Se rompió la racha consecutiva
            }
        }
    }
}

// --- CÁLCULO DE SENIORITY ---
let seniority = "Unknown";
if (consecutive_years > 0 && consecutive_years <= 5) seniority = "Early";
else if (consecutive_years > 5 && consecutive_years <= 12) seniority = "Mid";
else if (consecutive_years > 12) seniority = "Senior";

// --- CREAR LA FILA FINAL ENRIQUECIDA ---
return {
    json: {
        ...originalData,
        PROFILE_ID: originalData.AUTHOR_ID, 
        hindex: hindex,
        i10index: i10index,
        total_citations: total_citations,
        consecutive_years: consecutive_years,
        seniority: seniority,
        keywords: keywords,
        AFFILIATION: affiliation 
    }
};

const originalData = $('Loop Authors OpenAlex').item.json;
return {
    json: {
        ...originalData,
        PROFILE_ID: originalData.AUTHOR_ID, 
        hindex: 0,
        i10index: 0,
        total_citations: 0,
        consecutive_years: 0,
        seniority: "Unknown",
        keywords: "No data"
    }
};

// 1. Rescatamos los datos del autor (extraídos en el loop previo de Scopus)
