let seniority = "Unknown";

// --- 1. LÓGICA PARA AFILIACIÓN (Corregida) ---
let currentAffiliation = originalData.AFFILIATION_PAPER || "No affiliation";

// Si el paper no traía afiliación útil, buscamos agresivamente en el perfil
if (currentAffiliation === "No affiliation" || currentAffiliation === "No data" || currentAffiliation === "") {
    if (profile.affiliations && Array.isArray(profile.affiliations) && profile.affiliations.length > 0) {
        // Extraemos strings limpias, ignorando valores vacíos o nulos
        const validAffils = profile.affiliations
            .map(a => typeof a === 'object' ? (a.name || a.affiliation || JSON.stringify(a)) : a)
            .filter(a => a && a.trim() !== "");

        if (validAffils.length > 0) {
             currentAffiliation = validAffils.join(" | ");
        }
    }
}

// Determinamos si necesitamos el LLM para el país basados en la nueva afiliación
let countryRaw = "UNKNOWN";
// Solo marcamos "Need LLM extraction" si REALMENTE tenemos texto para analizar
if (currentAffiliation && currentAffiliation !== "No affiliation" && currentAffiliation !== "No data" && currentAffiliation !== "") {
    countryRaw = "Need LLM extraction"; 
}

// --- 2. LÓGICA PARA ORCID (Búsqueda Agresiva) ---
let orcidId = "NO_ORCID";
// Semantic Scholar a veces esconde el ORCID en externalIds (y a veces con mayúsculas/minúsculas diferentes)
if (profile.externalIds) {
    if (profile.externalIds.ORCID) {
        orcidId = profile.externalIds.ORCID.replace("http://orcid.org/", "").replace("https://orcid.org/", "");
    } else if (profile.externalIds.orcid) {
        orcidId = profile.externalIds.orcid.replace("http://orcid.org/", "").replace("https://orcid.org/", "");
    }
}

// --- 3. CÁLCULO DE SENIORITY ---
if (profile.papers && profile.papers.length > 0) {
    let years = profile.papers.map(p => parseInt(p.year)).filter(y => !isNaN(y));

    if (years.length > 0) {
        let uniqueYears = [...new Set(years)].sort((a,b) => b - a);

        consecutive_years = 1;
        let current = uniqueYears[0];
        for (let i = 1; i < uniqueYears.length; i++) {
            if (uniqueYears[i] === current - 1) {
                consecutive_years++;
                current = uniqueYears[i];
            } else break; 
        }

        let firstYear = Math.min(...uniqueYears);
        let careerLength = new Date().getFullYear() - firstYear; 
        if (careerLength > 15) seniority = "Senior";
        else if (careerLength >= 5) seniority = "Mid";
        else seniority = "Early";
    }
}

